using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using UnityEditor.SceneManagement;

// === 1. Ensure the scene is open ===
var scene = UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene();
if (scene.name != "LightningSkillDemo")
{
    UnityEditor.SceneManagement.EditorSceneManager.OpenScene("Assets/Scenes/LightningSkillDemo.unity");
    scene = UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene();
}

// === 2. Create Ground ===
var ground = GameObject.CreatePrimitive(PrimitiveType.Plane);
ground.name = "Ground";
ground.transform.position = Vector3.zero;
ground.transform.localScale = new Vector3(4f, 1f, 4f); // 40x40 units
var groundMat = new Material(Shader.Find("Standard"));
groundMat.color = new Color(0.25f, 0.35f, 0.2f); // Dark green grass
ground.GetComponent<Renderer>().material = groundMat;
ground.layer = LayerMask.NameToLayer("Ground") != 0 ? LayerMask.NameToLayer("Ground") : 0;

// === 3. Set up Camera ===
var cam = Camera.main;
if (cam == null)
{
    var camObj = new GameObject("Main Camera");
    cam = camObj.AddComponent<Camera>();
    camObj.AddComponent<AudioListener>();
    camObj.tag = "MainCamera";
}
cam.transform.position = new Vector3(0f, 25f, -15f);
cam.transform.rotation = Quaternion.Euler(55f, 0f, 0f);
cam.clearFlags = CameraClearFlags.SolidColor;
cam.backgroundColor = new Color(0.1f, 0.1f, 0.15f);
cam.orthographic = true;
cam.orthographicSize = 15f;

// === 4. Create Directional Light ===
var lightObj = new GameObject("Directional Light");
var dLight = lightObj.AddComponent<Light>();
dLight.type = LightType.Directional;
dLight.color = Color.white;
dLight.intensity = 1f;
lightObj.transform.rotation = Quaternion.Euler(50f, -30f, 0f);

// === 5. Create Range Indicator (circle) ===
var rangeObj = new GameObject("RangeIndicator");
// Use a LineRenderer to draw a circle
var rangeLR = rangeObj.AddComponent<LineRenderer>();
int segments = 64;
rangeLR.positionCount = segments + 1;
rangeLR.useWorldSpace = false;
rangeLR.startWidth = 0.08f;
rangeLR.endWidth = 0.08f;
rangeLR.loop = true;
rangeLR.startColor = new Color(0.3f, 0.6f, 1f, 0.8f);
rangeLR.endColor = new Color(0.3f, 0.6f, 1f, 0.8f);

// Default material for LineRenderer
var rangeMat = new Material(Shader.Find("Particles/Alpha Blended Premultiply"));
rangeLR.material = rangeMat;

float radius = 5f;
for (int i = 0; i <= segments; i++)
{
    float angle = (float)i / segments * Mathf.PI * 2f;
    float x = Mathf.Cos(angle) * radius;
    float z = Mathf.Sin(angle) * radius;
    rangeLR.SetPosition(i, new Vector3(x, 0.01f, z));
}
rangeObj.SetActive(false);

// === 6. Create Lightning Bolt Prefab ===
var boltObj = new GameObject("LightningBolt");
var boltLR = boltObj.AddComponent<LineRenderer>();
var boltMat = new Material(Shader.Find("Particles/Alpha Blended Premultiply"));
boltLR.material = boltMat;
boltLR.startWidth = 0.15f;
boltLR.endWidth = 0.05f;
boltLR.startColor = new Color(0.6f, 0.8f, 1f, 1f);
boltLR.endColor = new Color(0.3f, 0.5f, 1f, 0f);
boltLR.positionCount = 2;
boltLR.SetPosition(0, Vector3.zero);
boltLR.SetPosition(1, Vector3.up);
boltObj.AddComponent<LightningBolt>();

// Save as prefab
if (!AssetDatabase.IsValidFolder("Assets/Prefabs"))
    AssetDatabase.CreateFolder("Assets", "Prefabs");
if (!AssetDatabase.IsValidFolder("Assets/Prefabs/Skills"))
    AssetDatabase.CreateFolder("Assets/Prefabs", "Skills");

var boltPrefab = PrefabUtility.SaveAsPrefabAsset(boltObj, "Assets/Prefabs/Skills/LightningBolt.prefab");
Object.DestroyImmediate(boltObj);

// === 7. Create Lightning Impact Particle System ===
var impactObj = new GameObject("LightningImpact");
var psMain = impactObj.AddComponent<ParticleSystem>().main;
psMain.startColor = new Color(0.5f, 0.7f, 1f, 1f);
psMain.startSize = 0.5f;
psMain.startSpeed = 3f;
psMain.startLifetime = 0.6f;
psMain.maxParticles = 60;
psMain.simulationSpace = ParticleSystemSimulationSpace.World;

var ps = impactObj.GetComponent<ParticleSystem>();

// Emission
var emission = ps.emission;
emission.rateOverTime = 0;
emission.SetBursts(new ParticleSystem.Burst[] {
    new ParticleSystem.Burst(0f, 30)
});

// Shape - sphere
var shape = ps.shape;
shape.shapeType = ParticleSystemShapeType.Sphere;
shape.radius = 2f;

// Size over lifetime
var sizeOverLifetime = ps.sizeOverLifetime;
sizeOverLifetime.enabled = true;
sizeOverLifetime.size = new ParticleSystem.MinMaxCurve(1f, AnimationCurve.EaseInOut(0f, 1f, 1f, 0f));

// Color over lifetime
var colorOverLifetime = ps.colorOverLifetime;
colorOverLifetime.enabled = true;
var gradient = new Gradient();
gradient.SetKeys(
    new GradientColorKey[] { new GradientColorKey(new Color(0.6f, 0.8f, 1f), 0f), new GradientColorKey(new Color(0.3f, 0.5f, 1f), 1f) },
    new GradientAlphaKey[] { new GradientAlphaKey(1f, 0f), new GradientAlphaKey(0f, 1f) }
);
colorOverLifetime.color = new ParticleSystem.MinMaxGradient(gradient);

// Noise for flicker
var noise = ps.noise;
noise.enabled = true;
noise.strength = 1f;
noise.frequency = 3f;

// Add spark sub-emitter
var sparkObj = new GameObject("Sparks");
sparkObj.transform.parent = impactObj.transform;
var sparkPS = sparkObj.AddComponent<ParticleSystem>();
var sparkMain = sparkPS.main;
sparkMain.startColor = new Color(1f, 1f, 0.8f, 1f);
sparkMain.startSize = 0.15f;
sparkMain.startSpeed = 6f;
sparkMain.startLifetime = 0.4f;
sparkMain.maxParticles = 40;
sparkMain.simulationSpace = ParticleSystemSimulationSpace.World;

var sparkEmission = sparkPS.emission;
sparkEmission.rateOverTime = 0;
sparkEmission.SetBursts(new ParticleSystem.Burst[] {
    new ParticleSystem.Burst(0f, 20)
});

var sparkShape = sparkPS.shape;
sparkShape.shapeType = ParticleSystemShapeType.Sphere;
sparkShape.radius = 1f;

var sparkPSRenderer = sparkPS.GetComponent<ParticleSystemRenderer>();
sparkPSRenderer.material = new Material(Shader.Find("Particles/Alpha Blended Premultiply"));

// Add a glow light
var glowLight = impactObj.AddComponent<Light>();
glowLight.color = new Color(0.5f, 0.7f, 1f);
glowLight.intensity = 3f;
glowLight.range = 10f;
glowLight.type = LightType.Point;

var psRenderer = impactObj.GetComponent<ParticleSystemRenderer>();
psRenderer.material = new Material(Shader.Find("Particles/Alpha Blended Premultiply"));

var impactPrefab = PrefabUtility.SaveAsPrefabAsset(impactObj, "Assets/Prefabs/Skills/LightningImpact.prefab");
Object.DestroyImmediate(impactObj);

// === 8. Create Skill Controller Object ===
var controllerObj = new GameObject("LightningSkillController");
var ctrl = controllerObj.AddComponent<LightningSkillController>();

// Set references via SerializedObject
var so = new SerializedObject(ctrl);
so.FindProperty("_skillRange").floatValue = 5f;
so.FindProperty("_boltCount").intValue = 5;
so.FindProperty("_boltInterval").floatValue = 0.08f;
so.FindProperty("_boltHeight").floatValue = 15f;
so.FindProperty("_cooldown").floatValue = 8f;
so.FindProperty("_rangeIndicator").objectReferenceValue = rangeObj;
so.FindProperty("_lightningImpactPrefab").objectReferenceValue = impactPrefab;
so.FindProperty("_lightningBoltPrefab").objectReferenceValue = boltPrefab;
so.FindProperty("_mainCamera").objectReferenceValue = cam;
so.ApplyModifiedProperties();

// Add AudioSource
var audioSrc = controllerObj.AddComponent<AudioSource>();
so = new SerializedObject(ctrl);
so.FindProperty("_audioSource").objectReferenceValue = audioSrc;
so.ApplyModifiedProperties();

// === 9. Create UI Canvas with Skill Button ===
var canvasObj = new GameObject("Canvas");
var canvas = canvasObj.AddComponent<Canvas>();
canvas.renderMode = RenderMode.ScreenSpaceOverlay;
canvasObj.AddComponent<CanvasScaler>();
canvasObj.AddComponent<GraphicRaycaster>();

// Skill button
var buttonObj = new GameObject("SkillButton_Lightning");
buttonObj.transform.parent = canvasObj.transform;
var btnRect = buttonObj.AddComponent<RectTransform>();
btnRect.anchorMin = new Vector2(0.5f, 0f);
btnRect.anchorMax = new Vector2(0.5f, 0f);
btnRect.pivot = new Vector2(0.5f, 0.5f);
btnRect.anchoredPosition = new Vector2(0f, 60f);
btnRect.sizeDelta = new Vector2(70f, 70f);

var btnImage = buttonObj.AddComponent<Image>();
btnImage.color = new Color(0.2f, 0.3f, 0.6f, 0.9f);
var btnOutline = buttonObj.AddComponent<Outline>();
btnOutline.effectColor = new Color(0.3f, 0.6f, 1f, 1f);
btnOutline.effectDistance = new Vector2(2f, -2f);

var button = buttonObj.AddComponent<Button>();
var colors = button.colors;
colors.normalColor = new Color(0.2f, 0.3f, 0.6f);
colors.highlightedColor = new Color(0.3f, 0.5f, 0.9f);
colors.pressedColor = new Color(0.15f, 0.25f, 0.5f);
button.colors = colors;

// Icon text (lightning symbol)
var iconObj = new GameObject("Icon");
iconObj.transform.parent = buttonObj.transform;
var iconRect = iconObj.AddComponent<RectTransform>();
iconRect.anchorMin = Vector2.zero;
iconRect.anchorMax = Vector2.one;
iconRect.offsetMin = Vector2.zero;
iconRect.offsetMax = Vector2.zero;
var iconText = iconObj.AddComponent<Text>();
iconText.text = "⚡";
iconText.fontSize = 36;
iconText.alignment = TextAnchor.MiddleCenter;
iconText.color = new Color(0.7f, 0.9f, 1f);
iconText.font = Resources.GetBuiltinResource<Font>("Arial.ttf");

// Cooldown overlay text
var cdObj = new GameObject("CooldownText");
cdObj.transform.parent = buttonObj.transform;
var cdRect = cdObj.AddComponent<RectTransform>();
cdRect.anchorMin = Vector2.zero;
cdRect.anchorMax = Vector2.one;
cdRect.offsetMin = Vector2.zero;
cdRect.offsetMax = Vector2.zero;
var cdText = cdObj.AddComponent<Text>();
cdText.text = "";
cdText.fontSize = 20;
cdText.alignment = TextAnchor.MiddleCenter;
cdText.color = Color.white;
cdText.font = Resources.GetBuiltinResource<Font>("Arial.ttf");

// Wire button to controller
so = new SerializedObject(ctrl);
so.FindProperty("_skillButton").objectReferenceValue = button;
so.ApplyModifiedProperties();

// === 10. Add EventSystem ===
var esObj = GameObject.Find("EventSystem");
if (esObj == null)
{
    esObj = new GameObject("EventSystem");
    esObj.AddComponent<EventSystem>();
    esObj.AddComponent<StandaloneInputModule>();
}

// === 11. Save ===
UnityEditor.SceneManagement.EditorSceneManager.SaveScene(scene);

Debug.Log("LightningSkillDemo scene built successfully!");
Debug.Log($"- Ground: {ground.name}");
Debug.Log($"- Range Indicator: {rangeObj.name}");
Debug.Log($"- Lightning Bolt Prefab: {boltPrefab.name}");
Debug.Log($"- Lightning Impact Prefab: {impactPrefab.name}");
Debug.Log($"- Controller: {controllerObj.name}");
Debug.Log($"- UI: {buttonObj.name}");

providedArgs.script:
using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using UnityEditor.SceneManagement;

// === 1. Ensure the scene is open ===
var scene = UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene();
if (scene.name != "LightningSkillDemo")
{
    UnityEditor.SceneManagement.EditorSceneManager.OpenScene("Assets/Scenes/LightningSkillDemo.unity");
    scene = UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene();
}

// === 2. Create Ground ===
var ground = GameObject.CreatePrimitive(PrimitiveType.Plane);
ground.name = "Ground";
ground.transform.position = Vector3.zero;
ground.transform.localScale = new Vector3(4f, 1f, 4f); // 40x40 units
var groundMat = new Material(Shader.Find("Standard"));
groundMat.color = new Color(0.25f, 0.35f, 0.2f); // Dark green grass
ground.GetComponent<Renderer>().material = groundMat;
ground.layer = LayerMask.NameToLayer("Ground") != 0 ? LayerMask.NameToLayer("Ground") : 0;

// === 3. Set up Camera ===
var cam = Camera.main;
if (cam == null)
{
    var camObj = new GameObject("Main Camera");
    cam = camObj.AddComponent<Camera>();
    camObj.AddComponent<AudioListener>();
    camObj.tag = "MainCamera";
}
cam.transform.position = new Vector3(0f, 25f, -15f);
cam.transform.rotation = Quaternion.Euler(55f, 0f, 0f);
cam.clearFlags = CameraClearFlags.SolidColor;
cam.backgroundColor = new Color(0.1f, 0.1f, 0.15f);
cam.orthographic = true;
cam.orthographicSize = 15f;

// === 4. Create Directional Light ===
var lightObj = new GameObject("Directional Light");
var dLight = lightObj.AddComponent<Light>();
dLight.type = LightType.Directional;
dLight.color = Color.white;
dLight.intensity = 1f;
lightObj.transform.rotation = Quaternion.Euler(50f, -30f, 0f);

// === 5. Create Range Indicator (circle) ===
var rangeObj = new GameObject("RangeIndicator");
// Use a LineRenderer to draw a circle
var rangeLR = rangeObj.AddComponent<LineRenderer>();
int segments = 64;
rangeLR.positionCount = segments + 1;
rangeLR.useWorldSpace = false;
rangeLR.startWidth = 0.08f;
rangeLR.endWidth = 0.08f;
rangeLR.loop = true;
rangeLR.startColor = new Color(0.3f, 0.6f, 1f, 0.8f);
rangeLR.endColor = new Color(0.3f, 0.6f, 1f, 0.8f);

// Default material for LineRenderer
var rangeMat = new Material(Shader.Find("Particles/Alpha Blended Premultiply"));
rangeLR.material = rangeMat;

float radius = 5f;
for (int i = 0; i <= segments; i++)
{
    float angle = (float)i / segments * Mathf.PI * 2f;
    float x = Mathf.Cos(angle) * radius;
    float z = Mathf.Sin(angle) * radius;
    rangeLR.SetPosition(i, new Vector3(x, 0.01f, z));
}
rangeObj.SetActive(false);

// === 6. Create Lightning Bolt Prefab ===
var boltObj = new GameObject("LightningBolt");
var boltLR = boltObj.AddComponent<LineRenderer>();
var boltMat = new Material(Shader.Find("Particles/Alpha Blended Premultiply"));
boltLR.material = boltMat;
boltLR.startWidth = 0.15f;
boltLR.endWidth = 0.05f;
boltLR.startColor = new Color(0.6f, 0.8f, 1f, 1f);
boltLR.endColor = new Color(0.3f, 0.5f, 1f, 0f);
boltLR.positionCount = 2;
boltLR.SetPosition(0, Vector3.zero);
boltLR.SetPosition(1, Vector3.up);
boltObj.AddComponent<LightningBolt>();

// Save as prefab
if (!AssetDatabase.IsValidFolder("Assets/Prefabs"))
    AssetDatabase.CreateFolder("Assets", "Prefabs");
if (!AssetDatabase.IsValidFolder("Assets/Prefabs/Skills"))
    AssetDatabase.CreateFolder("Assets/Prefabs", "Skills");

var boltPrefab = PrefabUtility.SaveAsPrefabAsset(boltObj, "Assets/Prefabs/Skills/LightningBolt.prefab");
Object.DestroyImmediate(boltObj);

// === 7. Create Lightning Impact Particle System ===
var impactObj = new GameObject("LightningImpact");
var psMain = impactObj.AddComponent<ParticleSystem>().main;
psMain.startColor = new Color(0.5f, 0.7f, 1f, 1f);
psMain.startSize = 0.5f;
psMain.startSpeed = 3f;
psMain.startLifetime = 0.6f;
psMain.maxParticles = 60;
psMain.simulationSpace = ParticleSystemSimulationSpace.World;

var ps = impactObj.GetComponent<ParticleSystem>();

// Emission
var emission = ps.emission;
emission.rateOverTime = 0;
emission.SetBursts(new ParticleSystem.Burst[] {
    new ParticleSystem.Burst(0f, 30)
});

// Shape - sphere
var shape = ps.shape;
shape.shapeType = ParticleSystemShapeType.Sphere;
shape.radius = 2f;

// Size over lifetime
var sizeOverLifetime = ps.sizeOverLifetime;
sizeOverLifetime.enabled = true;
sizeOverLifetime.size = new ParticleSystem.MinMaxCurve(1f, AnimationCurve.EaseInOut(0f, 1f, 1f, 0f));

// Color over lifetime
var colorOverLifetime = ps.colorOverLifetime;
colorOverLifetime.enabled = true;
var gradient = new Gradient();
gradient.SetKeys(
    new GradientColorKey[] { new GradientColorKey(new Color(0.6f, 0.8f, 1f), 0f), new GradientColorKey(new Color(0.3f, 0.5f, 1f), 1f) },
    new GradientAlphaKey[] { new GradientAlphaKey(1f, 0f), new GradientAlphaKey(0f, 1f) }
);
colorOverLifetime.color = new ParticleSystem.MinMaxGradient(gradient);

// Noise for flicker
var noise = ps.noise;
noise.enabled = true;
noise.strength = 1f;
noise.frequency = 3f;

// Add spark sub-emitter
var sparkObj = new GameObject("Sparks");
sparkObj.transform.parent = impactObj.transform;
var sparkPS = sparkObj.AddComponent<ParticleSystem>();
var sparkMain = sparkPS.main;
sparkMain.startColor = new Color(1f, 1f, 0.8f, 1f);
sparkMain.startSize = 0.15f;
sparkMain.startSpeed = 6f;
sparkMain.startLifetime = 0.4f;
sparkMain.maxParticles = 40;
sparkMain.simulationSpace = ParticleSystemSimulationSpace.World;

var sparkEmission = sparkPS.emission;
sparkEmission.rateOverTime = 0;
sparkEmission.SetBursts(new ParticleSystem.Burst[] {
    new ParticleSystem.Burst(0f, 20)
});

var sparkShape = sparkPS.shape;
sparkShape.shapeType = ParticleSystemShapeType.Sphere;
sparkShape.radius = 1f;

var sparkPSRenderer = sparkPS.GetComponent<ParticleSystemRenderer>();
sparkPSRenderer.material = new Material(Shader.Find("Particles/Alpha Blended Premultiply"));

// Add a glow light
var glowLight = impactObj.AddComponent<Light>();
glowLight.color = new Color(0.5f, 0.7f, 1f);
glowLight.intensity = 3f;
glowLight.range = 10f;
glowLight.type = LightType.Point;

var psRenderer = impactObj.GetComponent<ParticleSystemRenderer>();
psRenderer.material = new Material(Shader.Find("Particles/Alpha Blended Premultiply"));

var impactPrefab = PrefabUtility.SaveAsPrefabAsset(impactObj, "Assets/Prefabs/Skills/LightningImpact.prefab");
Object.DestroyImmediate(impactObj);

// === 8. Create Skill Controller Object ===
var controllerObj = new GameObject("LightningSkillController");
var ctrl = controllerObj.AddComponent<LightningSkillController>();

// Set references via SerializedObject
var so = new SerializedObject(ctrl);
so.FindProperty("_skillRange").floatValue = 5f;
so.FindProperty("_boltCount").intValue = 5;
so.FindProperty("_boltInterval").floatValue = 0.08f;
so.FindProperty("_boltHeight").floatValue = 15f;
so.FindProperty("_cooldown").floatValue = 8f;
so.FindProperty("_rangeIndicator").objectReferenceValue = rangeObj;
so.FindProperty("_lightningImpactPrefab").objectReferenceValue = impactPrefab;
so.FindProperty("_lightningBoltPrefab").objectReferenceValue = boltPrefab;
so.FindProperty("_mainCamera").objectReferenceValue = cam;
so.ApplyModifiedProperties();

// Add AudioSource
var audioSrc = controllerObj.AddComponent<AudioSource>();
so = new SerializedObject(ctrl);
so.FindProperty("_audioSource").objectReferenceValue = audioSrc;
so.ApplyModifiedProperties();

// === 9. Create UI Canvas with Skill Button ===
var canvasObj = new GameObject("Canvas");
var canvas = canvasObj.AddComponent<Canvas>();
canvas.renderMode = RenderMode.ScreenSpaceOverlay;
canvasObj.AddComponent<CanvasScaler>();
canvasObj.AddComponent<GraphicRaycaster>();

// Skill button
var buttonObj = new GameObject("SkillButton_Lightning");
buttonObj.transform.parent = canvasObj.transform;
var btnRect = buttonObj.AddComponent<RectTransform>();
btnRect.anchorMin = new Vector2(0.5f, 0f);
btnRect.anchorMax = new Vector2(0.5f, 0f);
btnRect.pivot = new Vector2(0.5f, 0.5f);
btnRect.anchoredPosition = new Vector2(0f, 60f);
btnRect.sizeDelta = new Vector2(70f, 70f);

var btnImage = buttonObj.AddComponent<Image>();
btnImage.color = new Color(0.2f, 0.3f, 0.6f, 0.9f);
var btnOutline = buttonObj.AddComponent<Outline>();
btnOutline.effectColor = new Color(0.3f, 0.6f, 1f, 1f);
btnOutline.effectDistance = new Vector2(2f, -2f);

var button = buttonObj.AddComponent<Button>();
var colors = button.colors;
colors.normalColor = new Color(0.2f, 0.3f, 0.6f);
colors.highlightedColor = new Color(0.3f, 0.5f, 0.9f);
colors.pressedColor = new Color(0.15f, 0.25f, 0.5f);
button.colors = colors;

// Icon text (lightning symbol)
var iconObj = new GameObject("Icon");
iconObj.transform.parent = buttonObj.transform;
var iconRect = iconObj.AddComponent<RectTransform>();
iconRect.anchorMin = Vector2.zero;
iconRect.anchorMax = Vector2.one;
iconRect.offsetMin = Vector2.zero;
iconRect.offsetMax = Vector2.zero;
var iconText = iconObj.AddComponent<Text>();
iconText.text = "⚡";
iconText.fontSize = 36;
iconText.alignment = TextAnchor.MiddleCenter;
iconText.color = new Color(0.7f, 0.9f, 1f);
iconText.font = Resources.GetBuiltinResource<Font>("Arial.ttf");

// Cooldown overlay text
var cdObj = new GameObject("CooldownText");
cdObj.transform.parent = buttonObj.transform;
var cdRect = cdObj.AddComponent<RectTransform>();
cdRect.anchorMin = Vector2.zero;
cdRect.anchorMax = Vector2.one;
cdRect.offsetMin = Vector2.zero;
cdRect.offsetMax = Vector2.zero;
var cdText = cdObj.AddComponent<Text>();
cdText.text = "";
cdText.fontSize = 20;
cdText.alignment = TextAnchor.MiddleCenter;
cdText.color = Color.white;
cdText.font = Resources.GetBuiltinResource<Font>("Arial.ttf");

// Wire button to controller
so = new SerializedObject(ctrl);
so.FindProperty("_skillButton").objectReferenceValue = button;
so.ApplyModifiedProperties();

// === 10. Add EventSystem ===
var esObj = GameObject.Find("EventSystem");
if (esObj == null)
{
    esObj = new GameObject("EventSystem");
    esObj.AddComponent<EventSystem>();
    esObj.AddComponent<StandaloneInputModule>();
}

// === 11. Save ===
UnityEditor.SceneManagement.EditorSceneManager.SaveScene(scene);

Debug.Log("LightningSkillDemo scene built successfully!");
Debug.Log($"- Ground: {ground.name}");
Debug.Log($"- Range Indicator: {rangeObj.name}");
Debug.Log($"- Lightning Bolt Prefab: {boltPrefab.name}");
Debug.Log($"- Lightning Impact Prefab: {impactPrefab.name}");
Debug.Log($"- Controller: {controllerObj.name}");
Debug.Log($"- UI: {buttonObj.name}");

