args.script:
// Configure Camera
var cam = UnityEngine.Camera.main;
cam.orthographic = true;
cam.orthographicSize = 15f;
cam.clearFlags = CameraClearFlags.SolidColor;
cam.backgroundColor = new UnityEngine.Color(0.1f, 0.1f, 0.15f);

// Configure Light
var light = UnityEngine.Object.FindObjectOfType<UnityEngine.Light>();
light.type = UnityEngine.LightType.Directional;
light.color = UnityEngine.Color.white;
light.intensity = 1f;

// Configure Ground material
var ground = UnityEngine.GameObject.Find("Ground");
var gMat = new UnityEngine.Material(UnityEngine.Shader.Find("Standard"));
gMat.color = new UnityEngine.Color(0.25f, 0.35f, 0.2f);
ground.GetComponent<UnityEngine.Renderer>().material = gMat;

// Configure RangeIndicator LineRenderer (circle)
var rangeObj = UnityEngine.GameObject.Find("RangeIndicator");
var lr = rangeObj.GetComponent<UnityEngine.LineRenderer>();
int segments = 64;
lr.positionCount = segments + 1;
lr.useWorldSpace = false;
lr.startWidth = 0.1f;
lr.endWidth = 0.1f;
lr.loop = true;
lr.startColor = new UnityEngine.Color(0.3f, 0.6f, 1f, 0.8f);
lr.endColor = new UnityEngine.Color(0.3f, 0.6f, 1f, 0.8f);
var mat = new UnityEngine.Material(UnityEngine.Shader.Find("Particles/Alpha Blended Premultiply"));
lr.material = mat;

float radius = 5f;
for (int i = 0; i <= segments; i++)
{
    float angle = (float)i / segments * UnityEngine.Mathf.PI * 2f;
    float x = UnityEngine.Mathf.Cos(angle) * radius;
    float z = UnityEngine.Mathf.Sin(angle) * radius;
    lr.SetPosition(i, new UnityEngine.Vector3(x, 0.01f, z));
}
rangeObj.SetActive(false);

UnityEngine.Debug.Log("Camera, Light, Ground, RangeIndicator configured!");

