var rangeObj = UnityEngine.GameObject.Find("RangeIndicator");
var lr = rangeObj.GetComponent<UnityEngine.LineRenderer>();
int segments = 64;
lr.positionCount = segments + 1;
lr.useWorldSpace = false;
lr.startWidth = 0.1f;
