// Try to find a shader, fallback to Default
var shader = UnityEngine.Shader.Find("Particles/Alpha Blended");
if (shader == null) shader = UnityEngine.Shader.Find("Unlit/Color");
if (shader == null) shader = UnityEngine.Shader.Find("Sprites/Default");
if (shader != null) lr.material = new UnityEngine.Material(shader);
// else keep default LineRenderer material

float radius = 5f;
for (int i = 0; i <= segments; i++)
{
    float angle = (float)i / segments * UnityEngine.Mathf.PI * 2f;
    float x = UnityEngine.Mathf.Cos(angle) * radius;
    float z = UnityEngine.Mathf.Sin(angle) * radius;
    lr.SetPosition(i, new UnityEngine.Vector3(x, 0.01f, z));
}
rangeObj.SetActive(false);

UnityEngine.Debug.Log("RangeIndicator configured! Shader: " + (shader != null ? shader.name : "default"));

