var ps = impactObj.AddComponent<UnityEngine.ParticleSystem>();
var main = ps.main;
main.startColor = new UnityEngine.Color(0.5f, 0.7f, 1f, 1f);
main.startSize = 0.5f;
main.startSpeed = 3f;
main.startLifetime = 0.6f;
main.maxParticles = 60;
main.simulationSpace = UnityEngine.ParticleSystemSimulationSpace.World;

// Emission burst
var emission = ps.emission;
emission.rateOverTime = 0;
emission.SetBursts(new UnityEngine.ParticleSystem.Burst[] {
    new UnityEngine.ParticleSystem.Burst(0f, 30)
});

// Shape
var shape = ps.shape;
shape.shapeType = UnityEngine.ParticleSystemShapeType.Sphere;
shape.radius = 2f;

// Size over lifetime
var sizeOL = ps.sizeOverLifetime;
sizeOL.enabled = true;
sizeOL.size = new UnityEngine.ParticleSystem.MinMaxCurve(1f, 
    UnityEngine.AnimationCurve.EaseInOut(0f, 1f, 1f, 0f));

// Color over lifetime
var colOL = ps.colorOverLifetime;
colOL.enabled = true;
var grad = new UnityEngine.Gradient();
grad.SetKeys(
    new UnityEngine.GradientColorKey[] {
        new UnityEngine.GradientColorKey(new UnityEngine.Color(0.6f, 0.8f, 1f), 0f),
        new UnityEngine.GradientColorKey(new UnityEngine.Color(0.3f, 0.5f, 1f), 1f)
    },
    new UnityEngine.GradientAlphaKey[] {
        new UnityEngine.GradientAlphaKey(1f, 0f),
        new UnityEngine.GradientAlphaKey(0f, 1f)
    }
);
colOL.color = new UnityEngine.ParticleSystem.MinMaxGradient(grad);

// Noise
var noise = ps.noise;
noise.enabled = true;
noise.strength = 1f;
noise.frequency = 3f;

// Material
var psRenderer = impactObj.GetComponent<UnityEngine.ParticleSystemRenderer>();
var pShader = UnityEngine.Shader.Find("Particles/Alpha Blended");
if (pShader == null) pShader = UnityEngine.Shader.Find("Unlit/Color");
if (pShader != null) psRenderer.material = new UnityEngine.Material(pShader);

// Glow light
var glow = impactObj.AddComponent<UnityEngine.Light>();
glow.color = new UnityEngine.Color(0.5f, 0.7f, 1f);
glow.intensity = 3f;
glow.range = 10f;
glow.type = UnityEngine.LightType.Point;

// Stop auto-play
ps.Stop(true);

var impactPrefab = UnityEditor.PrefabUtility.SaveAsPrefabAsset(impactObj, "Assets/Prefabs/Skills/LightningImpact.prefab");
UnityEngine.Object.DestroyImmediate(impactObj);

UnityEngine.Debug.Log("LightningImpact prefab created!");

