args.script:
using UnityEngine.UI;
// Configure Canvas
var canvasObj = UnityEngine.GameObject.Find("Canvas");
var canvas = canvasObj.AddComponent<Canvas>();
canvas.renderMode = RenderMode.ScreenSpaceOverlay;
canvasObj.AddComponent<CanvasScaler>();
canvasObj.AddComponent<GraphicRaycaster>();

// Skill button
var btnObj = new UnityEngine.GameObject("SkillButton_Lightning");
btnObj.transform.SetParent(canvasObj.transform, false);
var btnRect = btnObj.AddComponent<RectTransform>();
btnRect.anchorMin = new UnityEngine.Vector2(0.5f, 0f);
btnRect.anchorMax = new UnityEngine.Vector2(0.5f, 0f);
btnRect.pivot = new UnityEngine.Vector2(0.5f, 0.5f);
btnRect.anchoredPosition = new UnityEngine.Vector2(0f, 60f);
btnRect.sizeDelta = new UnityEngine.Vector2(70f, 70f);

var btnImage = btnObj.AddComponent<Image>();
btnImage.color = new UnityEngine.Color(0.2f, 0.3f, 0.6f, 0.9f);
var outline = btnObj.AddComponent<Outline>();
outline.effectColor = new UnityEngine.Color(0.3f, 0.6f, 1f, 1f);
outline.effectDistance = new UnityEngine.Vector2(2f, -2f);

var button = btnObj.AddComponent<Button>();

// Icon
var iconObj = new UnityEngine.GameObject("Icon");
iconObj.transform.SetParent(btnObj.transform, false);
var iconRect = iconObj.AddComponent<RectTransform>();
iconRect.anchorMin = UnityEngine.Vector2.zero;
iconRect.anchorMax = UnityEngine.Vector2.one;
iconRect.offsetMin = UnityEngine.Vector2.zero;
iconRect.offsetMax = UnityEngine.Vector2.zero;
var iconText = iconObj.AddComponent<Text>();
iconText.text = "\u26A1";
iconText.fontSize = 36;
iconText.alignment = TextAnchor.MiddleCenter;
iconText.color = new UnityEngine.Color(0.7f, 0.9f, 1f);

// Wire button
var ctrlObj = UnityEngine.GameObject.Find("LightningSkillController");
if (ctrlObj != null)
{
    var so = new UnityEditor.SerializedObject(ctrlObj.GetComponent<LightningSkillController>());
    so.FindProperty("_skillButton").objectReferenceValue = button;
    so.ApplyModifiedProperties();
}

// EventSystem
var esObj = UnityEngine.GameObject.Find("EventSystem");
if (esObj == null)
{
    esObj = new UnityEngine.GameObject("EventSystem");
    esObj.AddComponent<EventSystem>();
    esObj.AddComponent<StandaloneInputModule>();
}

