using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using UnityEditor.SceneManagement;

public static class LightningSkillSetup
{
    [MenuItem("Tools/Lightning Skill/Setup UI")]
    public static void SetupUI()
    {
        var canvasObj = GameObject.Find("Canvas");
        if (canvasObj == null)
        {
            canvasObj = new GameObject("Canvas");
        }

        var canvas = canvasObj.GetComponent<Canvas>();
        if (canvas == null)
        {
            canvas = canvasObj.AddComponent<Canvas>();
        }
        canvas.renderMode = RenderMode.ScreenSpaceOverlay;

        if (canvasObj.GetComponent<CanvasScaler>() == null)
            canvasObj.AddComponent<CanvasScaler>();
        if (canvasObj.GetComponent<GraphicRaycaster>() == null)
            canvasObj.AddComponent<GraphicRaycaster>();

        // Skill button
        var btnObj = new GameObject("SkillButton_Lightning");
        btnObj.transform.SetParent(canvasObj.transform, false);
        var btnRect = btnObj.AddComponent<RectTransform>();
        btnRect.anchorMin = new Vector2(0.5f, 0f);
        btnRect.anchorMax = new Vector2(0.5f, 0f);
        btnRect.pivot = new Vector2(0.5f, 0.5f);
        btnRect.anchoredPosition = new Vector2(0f, 60f);
        btnRect.sizeDelta = new Vector2(70f, 70f);

        var btnImage = btnObj.AddComponent<Image>();
        btnImage.color = new Color(0.2f, 0.3f, 0.6f, 0.9f);
        var outline = btnObj.AddComponent<Outline>();
        outline.effectColor = new Color(0.3f, 0.6f, 1f, 1f);
        outline.effectDistance = new Vector2(2f, -2f);
        var button = btnObj.AddComponent<Button>();

        // Icon
        var iconObj = new GameObject("Icon");
        iconObj.transform.SetParent(btnObj.transform, false);
        var iconRect = iconObj.AddComponent<RectTransform>();
        iconRect.anchorMin = Vector2.zero;
        iconRect.anchorMax = Vector2.one;
        iconRect.offsetMin = Vector2.zero;
        iconRect.offsetMax = Vector2.zero;
        var iconText = iconObj.AddComponent<Text>();
        iconText.text = "\u26A1";
        iconText.fontSize = 36;
        iconText.alignment = TextAnchor.MiddleCenter;
        iconText.color = new Color(0.7f, 0.9f, 1f);

        // Wire button to controller
        var ctrlObj = GameObject.Find("LightningSkillController");
        if (ctrlObj != null)
        {
            var so = new SerializedObject(ctrlObj.GetComponent<LightningSkillController>());
            so.FindProperty("_skillButton").objectReferenceValue = button;
            so.ApplyModifiedProperties();
        }

        // EventSystem
        var esObj = GameObject.Find("EventSystem");
        if (esObj == null)
        {
            esObj = new GameObject("EventSystem");
            esObj.AddComponent<EventSystem>();
            esObj.AddComponent<StandaloneInputModule>();
        }

        var scene = UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene();
        UnityEditor.SceneManagement.EditorSceneManager.MarkSceneDirty(scene);

        Debug.Log("Lightning Skill UI created successfully!");
    }
}

