args.script:
// Add some decorative tower cubes to make the scene look more like a TD
for (int i = 0; i < 6; i++)
{
    float angle = i * 60f * UnityEngine.Mathf.Deg2Rad;
    float x = UnityEngine.Mathf.Cos(angle) * 10f;
    float z = UnityEngine.Mathf.Sin(angle) * 10f;

    var tower = UnityEngine.GameObject.CreatePrimitive(UnityEngine.PrimitiveType.Cube);
    tower.name = "Tower_" + i;
    tower.transform.position = new UnityEngine.Vector3(x, 1f, z);
    tower.transform.localScale = new UnityEngine.Vector3(1.5f, 2f, 1.5f);

    var mat = new UnityEngine.Material(UnityEngine.Shader.Find("Standard"));
    mat.color = new UnityEngine.Color(0.4f, 0.4f, 0.45f);
    tower.GetComponent<UnityEngine.Renderer>().material = mat;
}

// Add a center structure
var center = UnityEngine.GameObject.CreatePrimitive(UnityEngine.PrimitiveType.Cylinder);
center.name = "CenterStructure";
center.transform.position = new UnityEngine.Vector3(0f, 1.5f, 0f);
center.transform.localScale = new UnityEngine.Vector3(3f, 1.5f, 3f);
var centerMat = new UnityEngine.Material(UnityEngine.Shader.Find("Standard"));
centerMat.color = new UnityEngine.Color(0.5f, 0.4f, 0.3f);
center.GetComponent<UnityEngine.Renderer>().material = centerMat;

UnityEngine.Debug.Log("Decorative towers added!");

