// Find by instanceID since it's inactive
var rangeObj = (UnityEngine.GameObject)UnityEngine.Object.FindObjectOfType<UnityEngine.Transform>(true);
// Better approach: iterate all
var allTransforms = UnityEngine.Resources.FindObjectsOfTypeAll<UnityEngine.Transform>();
UnityEngine.GameObject rangeObjRef = null;
foreach (var t in allTransforms)
{
    if (t != null && t.name == "RangeIndicator" && t.gameObject.scene.isLoaded)
    {
        rangeObjRef = t.gameObject;
        break;
    }
}

if (rangeObjRef != null)
{
    var lr = rangeObjRef.GetComponent<UnityEngine.LineRenderer>();
    var mat = new UnityEngine.Material(UnityEngine.Shader.Find("Unlit/Transparent"));
    mat.color = new UnityEngine.Color(0.3f, 0.6f, 1f, 0.8f);
    lr.material = mat;
    rangeObjRef.SetActive(true);
    UnityEngine.Debug.Log("RangeIndicator fixed! Active: " + rangeObjRef.activeSelf);
}
else
{
    UnityEngine.Debug.LogError("RangeIndicator not found!");
}

