using UnityEngine;
using System.Collections;

/// <summary>
/// Procedural lightning bolt using LineRenderer.
/// Generates a jagged path from origin to target with random offsets.
/// </summary>
[RequireComponent(typeof(LineRenderer))]
public class LightningBolt : MonoBehaviour
{
    [Header("Bolt Settings")]
    [SerializeField] private int _segments = 10;
    [SerializeField] private float _jitter = 1.2f;
    [SerializeField] private float _duration = 0.4f;
    [SerializeField] private float _width = 0.4f;
    [SerializeField] private Color _startColor = new Color(0.7f, 0.85f, 1f, 1f);
    [SerializeField] private Color _endColor = new Color(0.3f, 0.5f, 1f, 0.2f);

    private LineRenderer _lr;
    private float _timer;

    public void Fire(Vector3 from, Vector3 to)
    {
        _lr = GetComponent<LineRenderer>();
        _lr.positionCount = _segments + 1;
        _lr.startWidth = _width;
        _lr.endWidth = _width * 0.3f;
        _lr.startColor = _startColor;
        _lr.endColor = _endColor;
        _lr.useWorldSpace = true;

        GeneratePath(from, to);
        _timer = _duration;
        StartCoroutine(AnimateBolt());
    }

    private void GeneratePath(Vector3 from, Vector3 to)
    {
        Vector3 dir = to - from;
        float dist = dir.magnitude;
        Vector3 perp = Vector3.Cross(dir.normalized, Vector3.up).normalized;

        _lr.SetPosition(0, from);
        for (int i = 1; i < _segments; i++)
        {
            float t = (float)i / _segments;
            Vector3 pos = Vector3.Lerp(from, to, t);
            pos += perp * Random.Range(-_jitter, _jitter);
            pos += Vector3.up * Random.Range(-_jitter * 0.3f, _jitter * 0.3f);
            _lr.SetPosition(i, pos);
        }
        _lr.SetPosition(_segments, to);
    }

    private IEnumerator AnimateBolt()
    {
        while (_timer > 0f)
        {
            _timer -= Time.deltaTime;
            float alpha = Mathf.Clamp01(_timer / _duration);
            _lr.startColor = new Color(_startColor.r, _startColor.g, _startColor.b, alpha);
            _lr.endColor = new Color(_endColor.r, _endColor.g, _endColor.b, alpha * 0.5f);

            // Re-jitter for flickering effect
            Vector3 from = _lr.GetPosition(0);
            Vector3 to = _lr.GetPosition(_segments);
            GeneratePath(from, to);

            yield return null;
        }
        Destroy(gameObject);
    }
}

